# Shapes module - defines shape interfaces and abstract base classes
interface IShape:
    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

    @abstract
    def describe(self) -> str: ...

interface IDrawable:
    @abstract
    def draw(self) -> str: ...

@abstract
class ShapeBase:
    _name: str

    def __init__(self, name: str):
        self._name = name

    property get name(self) -> str:
        return self._name

    @virtual
    def scale(self, factor: float) -> None:
        pass

