# Shape implementations module - concrete shape classes
from shapes import ShapeBase, IShape
from shapes import IDrawable
from geometry_types import Point, Color, LineStyle

class Rectangle(ShapeBase, IShape, IDrawable):
    _width: float
    _height: float
    _color: Color
    _line_style: LineStyle

    def __init__(self, w: float, h: float, color: Color, style: LineStyle):
        super().__init__("Rectangle")
        self._width = w
        self._height = h
        self._color = color
        self._line_style = style

    @override
    def area(self) -> float:
        return self._width * self._height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self._width + self._height)

    @override
    def describe(self) -> str:
        return f"{self._name}: {self._width}x{self._height}, color={self._color.name}"

    @override
    def draw(self) -> str:
        return f"Drawing rectangle with {self._line_style.name} lines"

    @override
    def scale(self, factor: float) -> None:
        self._width = self._width * factor
        self._height = self._height * factor

class Circle(ShapeBase, IShape, IDrawable):
    _radius: float
    _center: Point

    def __init__(self, radius: float, center: Point):
        super().__init__("Circle")
        self._radius = radius
        self._center = center

    @override
    def area(self) -> float:
        return 3.14159 * self._radius * self._radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self._radius

    @override
    def describe(self) -> str:
        return f"{self._name}: r={self._radius:.2f} at {self._center}"

    @override
    def draw(self) -> str:
        return f"Drawing circle at {self._center}"

    property get center_point(self) -> Point:
        return self._center

def create_default_rect() -> Rectangle:
    return Rectangle(10.0, 5.0, Color.BLUE, LineStyle.SOLID)

def create_unit_circle() -> Circle:
    return Circle(1.0, Point(0.0, 0.0))
